+                    "a",
+                    vec![Scalar::Float64(1.0), Scalar::Float64(2.0)],
+                ),
+                (
+                    "label",
+                    vec![
+                        Scalar::Utf8("x".into()),
+                        Scalar::Utf8("y".into()),
+                    ],
+                ),
+            ],
+        )
+        .unwrap();
+        let result = df.ewm(None, Some(0.5)).sum().unwrap();
+        assert_eq!(result.column_names(), vec!["a"]);
+    }
